import type { IStorage } from '@kyokuya/react-storage'
import { usePersisDataEffect } from '@kyokuya/react-storage'
import type { IGomokuGameState } from '../context/state'

const persistKeys: ReadonlyArray<keyof IGomokuGameState> = [
  'GOMOKU_SIZE',
  'players',
  'winner',
  'instructions',
  'activatedCell',
  'gameTick',
]

export const usePersistGomokuStateEffect = (
  storage: IStorage<Partial<IGomokuGameState>> | null,
  state: IGomokuGameState,
): void => {
  usePersisDataEffect<IGomokuGameState>(storage, state, persistKeys)
}
